class Solution {
    public long[] unmarkedSumArray(int[] nums, int[][] queries) {
        int n = nums.length;
        long[] answer = new long[queries.length];
        boolean[] marked = new boolean[n];
        long sum = 0;
        for (int num : nums) {
            if (!marked[nums.indexOf(num)]) {
                sum += num;
            }
        }
        for (int i = 0; i < queries.length; i++) {
            int index = queries[i][0];
            int k = queries[i][1];
            if (!marked[index]) {
                marked[index] = true;
                sum -= nums[index];
            }
            Arrays.sort(nums);
            for (int j = 0; j < k && j < n; j++) {
                if (!marked[j]) {
                    marked[j] = true;
                    sum -= nums[j];
                }
            }
            answer[i] = sum;
        }
        return answer;
    }
}
